import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink, ActivatedRoute, Router } from '@angular/router';
import { SeedService } from '../../data/seed.service';
import { Account, Quote } from '../../data/models';

interface Bar {
  label: string;
  value: number;
  pct: number;
  badgeClass?: string;
}

@Component({
  selector: 'app-reports',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './reports.component.html',
  styleUrl: './reports.component.css',
})
export class ReportsComponent {
  readonly tabs = ['revenue', 'winrate', 'backlog', 'otd', 'health', 'commission'];
  activeTab = signal('revenue');
  qbrAccountId = signal<string | null>(null);

  private pct(rows: Bar[]): Bar[] {
    const max = Math.max(1, ...rows.map((r) => r.value));
    rows.forEach((r) => (r.pct = Math.round((r.value / max) * 100)));
    return rows;
  }

  customerAccounts = computed<Account[]>(() =>
    this.seed.accounts().filter((a) => a.type === 'end-customer'),
  );

  // Stat cards up top.
  totalRevenue = computed(() => this.seed.accounts().reduce((s, a) => s + a.ytdRevenue, 0));
  totalBacklog = computed(() => this.seed.accounts().reduce((s, a) => s + a.backlogValue, 0));
  winRate = computed(() => {
    const decided = this.seed.quotes().filter((q) => q.status === 'won' || q.status === 'lost');
    if (decided.length === 0) return 0;
    return Math.round((decided.filter((q) => q.status === 'won').length / decided.length) * 100);
  });
  commissionDue = computed(() =>
    this.seed.commissions().reduce((s, c) => s + (c.commissionDue - c.paid), 0),
  );

  // revenue by account
  revenueBars = computed<Bar[]>(() =>
    this.pct(
      this.customerAccounts()
        .map((a) => ({ label: a.name, value: a.ytdRevenue, pct: 0 }))
        .sort((x, y) => y.value - x.value),
    ),
  );

  // winrate
  wonQuotes = computed<Quote[]>(() => this.seed.quotes().filter((q) => q.status === 'won'));
  lostQuotes = computed<Quote[]>(() => this.seed.quotes().filter((q) => q.status === 'lost'));
  winrateBars = computed<Bar[]>(() =>
    this.pct([
      { label: 'Won', value: this.wonQuotes().length, pct: 0, badgeClass: 'badge-success' },
      { label: 'Lost', value: this.lostQuotes().length, pct: 0, badgeClass: 'badge-danger' },
    ]),
  );

  // backlog by account
  backlogBars = computed<Bar[]>(() => {
    const map = new Map<string, number>();
    for (const o of this.seed.orders()) {
      map.set(o.accountName, (map.get(o.accountName) ?? 0) + o.amount);
    }
    return this.pct(
      Array.from(map.entries())
        .map(([label, value]) => ({ label, value, pct: 0 }))
        .sort((a, b) => b.value - a.value),
    );
  });

  // otd on-time vs slipping
  otdBars = computed<Bar[]>(() => {
    const total = this.seed.orders().length;
    const slipping = this.seed.orders().filter((o) => o.slippage).length;
    return this.pct([
      { label: 'On time', value: total - slipping, pct: 0, badgeClass: 'badge-success' },
      { label: 'Slipping', value: slipping, pct: 0, badgeClass: 'badge-danger' },
    ]);
  });

  // health by account, colored by connection level
  healthBars = computed<Bar[]>(() =>
    this.customerAccounts()
      .map((a) => ({
        label: a.name,
        value: a.healthScore,
        pct: a.healthScore,
        badgeClass: this.connectionClass(a.connectionLevel),
      }))
      .sort((x, y) => y.value - x.value),
  );

  // commission due vs paid
  commissionDueTotal = computed(() => this.seed.commissions().reduce((s, c) => s + c.commissionDue, 0));
  commissionPaidTotal = computed(() => this.seed.commissions().reduce((s, c) => s + c.paid, 0));

  qbrAccount = computed<Account | undefined>(() => {
    const id = this.qbrAccountId();
    return id ? this.seed.accountById(id) : undefined;
  });

  // Fabricated whitespace/next-actions per account for the QBR.
  qbrWhitespace = computed<string[]>(() => {
    const a = this.qbrAccount();
    if (!a) return [];
    return [
      `Expand ${a.industry} footprint beyond current backlog of $${a.backlogValue.toLocaleString()}`,
      `Introduce adjacent breaker families not yet quoted this year`,
      a.singleThreadRisk ? `Build a second relationship to reduce single-thread risk` : `Deepen multi-contact coverage to protect continuity`,
    ];
  });

  qbrNextActions = computed<string[]>(() => {
    const a = this.qbrAccount();
    if (!a) return [];
    return [
      `Schedule executive QBR review with ${a.name.split('—')[0].trim()}`,
      `Refresh forecast against ${a.openQuotes} open quote(s)`,
      a.connectionLevel === 'at-risk' ? `Prioritize reconnect to move health above 70` : `Sustain cadence to hold ${a.healthScore} health`,
    ];
  });

  connectionClass(level: string): string {
    switch (level) {
      case 'strong': return 'badge-success';
      case 'developing': return 'badge-warning';
      case 'at-risk': return 'badge-danger';
      default: return 'badge-neutral';
    }
  }

  setTab(tab: string): void {
    this.router.navigate([], { queryParams: { tab, panel: null, account: null }, queryParamsHandling: 'merge' });
  }

  openQbr(id: string): void {
    this.router.navigate([], { queryParams: { panel: 'qbr', account: id }, queryParamsHandling: 'merge' });
  }

  closeQbr(): void {
    this.router.navigate([], { queryParams: { panel: null, account: null }, queryParamsHandling: 'merge' });
  }

  constructor(public seed: SeedService, private route: ActivatedRoute, private router: Router) {
    this.route.queryParamMap.subscribe((q) => {
      const t = q.get('tab');
      this.activeTab.set(t && this.tabs.includes(t) ? t : 'revenue');
      this.qbrAccountId.set(q.get('panel') === 'qbr' ? q.get('account') : null);
    });
  }
}
